const notionPage = $('寫入請假記錄').item.json;
const managerResults = $input.all();
const w = $('Webhook').item.json;

const pageId = notionPage.id;
const managerUid = managerResults.length > 0
  ? (managerResults[0].json.properties?.['店長 Line UID']?.rich_text?.[0]?.plain_text ?? null)
  : null;

const note = w.note || '（無）';

const payload = {
  to: managerUid,
  messages: [{
    type: 'flex',
    altText: '📋 ' + w.name + ' 請假申請，請審核',
    contents: {
      type: 'bubble',
      header: {
        type: 'box', layout: 'vertical',
        backgroundColor: '#2D5A4B', paddingAll: '16px',
        contents: [{ type: 'text', text: '📋 請假申請', color: '#FFFFFF', weight: 'bold', size: 'lg' }]
      },
      body: {
        type: 'box', layout: 'vertical', spacing: 'sm', paddingAll: '16px',
        contents: [
          { type: 'box', layout: 'baseline', spacing: 'sm', contents: [
            { type: 'text', text: '員工', color: '#888888', size: 'sm', flex: 2 },
            { type: 'text', text: w.name + '（' + w.store + '）', wrap: true, size: 'sm', flex: 5 }
          ]},
          { type: 'box', layout: 'baseline', spacing: 'sm', contents: [
            { type: 'text', text: '假別', color: '#888888', size: 'sm', flex: 2 },
            { type: 'text', text: w.leaveType, wrap: true, size: 'sm', flex: 5 }
          ]},
          { type: 'box', layout: 'baseline', spacing: 'sm', contents: [
            { type: 'text', text: '日期', color: '#888888', size: 'sm', flex: 2 },
            { type: 'text', text: w.startDate + ' ' + w.startTime + ' 至 ' + w.endDate + ' ' + w.endTime, wrap: true, size: 'sm', flex: 5 }
          ]},
          { type: 'box', layout: 'baseline', spacing: 'sm', contents: [
            { type: 'text', text: '備註', color: '#888888', size: 'sm', flex: 2 },
            { type: 'text', text: note, wrap: true, size: 'sm', flex: 5 }
          ]}
        ]
      },
      footer: {
        type: 'box', layout: 'horizontal', spacing: 'sm', paddingAll: '12px',
        contents: [
          {
            type: 'button', style: 'primary', color: '#2D5A4B', height: 'sm',
            action: {
              type: 'postback', label: '✅ 核准',
              data: 'action=approve&pageId=' + pageId + '&employeeUid=' + w.lineUserId
            }
          },
          {
            type: 'button', style: 'secondary', height: 'sm',
            action: {
              type: 'postback', label: '❌ 拒絕',
              data: 'action=reject&pageId=' + pageId + '&employeeUid=' + w.lineUserId
            }
          }
        ]
      }
    }
  }]
};

return [{ json: payload }];
